import { useState } from "react";

const HEADS = "data:image/png;base64,";
const TAILS = "data:image/png;base64,";

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=DM+Mono:ital,wght@0,300;0,400;0,500;1,300;1,400&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    background: #fff;
    font-family: 'DM Mono', monospace;
    -webkit-font-smoothing: antialiased;
  }

  .app {
    min-height: 100vh;
    background: #fff;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 48px 24px;
  }

  .header {
    text-align: center;
    margin-bottom: 48px;
  }

  .brand {
    font-size: 18px;
    font-weight: 500;
    letter-spacing: -0.03em;
    color: #111;
    margin-bottom: 5px;
  }

  .brand span { color: #bbb; font-weight: 300; }

  .sub {
    font-size: 10px;
    font-weight: 300;
    letter-spacing: 0.22em;
    text-transform: uppercase;
    color: #ccc;
  }

  .coin-stage {
    width: 220px;
    height: 220px;
    perspective: 900px;
    margin-bottom: 48px;
  }

  .coin-wrap {
    width: 100%;
    height: 100%;
    position: relative;
    transform-style: preserve-3d;
  }

  .coin-wrap.spinning {
    animation: toss 1.5s cubic-bezier(0.33, 0, 0.66, 1) forwards;
  }

  @keyframes toss {
    0%   { transform: rotateY(var(--s)) translateY(0px); }
    20%  { transform: rotateY(calc(var(--s) + 360deg)) translateY(-55px); }
    50%  { transform: rotateY(calc(var(--s) + 900deg)) translateY(-80px); }
    75%  { transform: rotateY(calc(var(--s) + 1440deg)) translateY(-28px); }
    92%  { transform: rotateY(var(--e)) translateY(3px); }
    100% { transform: rotateY(var(--e)) translateY(0px); }
  }

  .face {
    position: absolute;
    inset: 0;
    border-radius: 50%;
    backface-visibility: hidden;
    -webkit-backface-visibility: hidden;
    overflow: hidden;
  }

  .face img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    border-radius: 50%;
    display: block;
  }

  .face.tails { transform: rotateY(180deg); }

  .result-area {
    text-align: center;
    margin-bottom: 28px;
    height: 44px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
  }

  .result-word {
    font-size: 22px;
    font-weight: 500;
    letter-spacing: -0.02em;
    color: #111;
    opacity: 0;
    transform: translateY(8px);
    transition: opacity 0.4s ease, transform 0.4s ease;
  }

  .result-word.show { opacity: 1; transform: translateY(0); }

  .result-meta {
    font-size: 10px;
    font-weight: 300;
    letter-spacing: 0.2em;
    text-transform: uppercase;
    color: #bbb;
    margin-top: 4px;
    opacity: 0;
    transition: opacity 0.4s ease 0.15s;
  }

  .result-meta.show { opacity: 1; }

  .flip-btn {
    font-family: 'DM Mono', monospace;
    font-size: 15px;
    font-weight: 500;
    letter-spacing: 0.28em;
    text-transform: uppercase;
    color: #fff;
    background: #111;
    border: none;
    border-radius: 999px;
    padding: 18px 72px;
    cursor: pointer;
    transition: background 0.18s, transform 0.12s;
    margin-bottom: 24px;
    display: block;
  }

  .flip-btn:hover:not(:disabled) { background: #333; }
  .flip-btn:active:not(:disabled) { transform: scale(0.97); }
  .flip-btn:disabled { background: #999; cursor: not-allowed; }

  /* ── TALLY CARD — compact ── */
  .tally-card {
    width: 100%;
    max-width: 300px;
    border: 1.5px solid #e8e8e8;
    border-radius: 16px;
    display: flex;
    align-items: stretch;
    margin-bottom: 18px;
    overflow: hidden;
  }

  .t-col {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 16px 10px;
  }

  .t-divider {
    width: 1px;
    background: #e8e8e8;
    margin: 14px 0;
  }

  .t-num {
    font-size: 24px;
    font-weight: 500;
    color: #111;
    line-height: 1;
    margin-bottom: 7px;
    letter-spacing: -0.02em;
  }

  .t-num.total { font-weight: 700; }

  .t-lbl {
    font-size: 9px;
    font-weight: 400;
    letter-spacing: 0.2em;
    text-transform: uppercase;
    color: #bbb;
  }

  .reset-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #ccc;
    transition: color 0.18s, transform 0.3s;
    border-radius: 50%;
  }

  .reset-btn:hover { color: #999; }
  .reset-btn:active { transform: rotate(180deg); color: #555; }

  .reset-btn svg {
    width: 22px;
    height: 22px;
  }
`;

const ResetIcon = () => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
    <path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8" />
    <path d="M3 3v5h5" />
  </svg>
);

export default function FlipDrop() {
  const [spin, setSpin] = useState(false);
  const [result, setResult] = useState(null);
  const [show, setShow] = useState(false);
  const [counts, setCounts] = useState({ heads: 0, tails: 0 });
  const [resting, setResting] = useState(0);
  const [endAngle, setEndAngle] = useState(0);

  const toss = () => {
    if (spin) return;
    setShow(false);
    setResult(null);
    const isHeads = Math.random() < 0.5;
    const extraFullSpins = (Math.floor(Math.random() * 3) + 6) * 360;
    const normResting = resting % 360;
    const targetFace = isHeads ? 0 : 180;
    const diff = ((targetFace - normResting) + 360) % 360;
    const newEnd = resting + extraFullSpins + diff;
    setEndAngle(newEnd);
    setSpin(true);
    setTimeout(() => {
      setSpin(false);
      setResting(newEnd);
      const r = isHeads ? "heads" : "tails";
      setResult(r);
      setCounts(c => ({ ...c, [r]: c[r] + 1 }));
      setTimeout(() => setShow(true), 80);
    }, 1500);
  };

  const reset = () => {
    if (spin) return;
    setCounts({ heads: 0, tails: 0 });
    setResult(null);
    setShow(false);
  };

  const total = counts.heads + counts.tails;
  const wrapStyle = spin
    ? { "--s": resting + "deg", "--e": endAngle + "deg" }
    : { transform: `rotateY(${resting}deg)` };

  return (
    <>
      <style>{styles}</style>
      <div className="app">
        <div className="header">
          <div className="brand">Flip<span>Drop</span></div>
          <div className="sub">Charles III · £2 · 2023</div>
        </div>

        <div className="coin-stage">
          <div className={"coin-wrap" + (spin ? " spinning" : "")} style={wrapStyle}>
            <div className="face heads"><img src={HEADS} alt="Heads" /></div>
            <div className="face tails"><img src={TAILS} alt="Tails" /></div>
          </div>
        </div>

        <div className="result-area">
          <div className={"result-word" + (show ? " show" : "")}>
            {result === "heads" ? "Heads" : result === "tails" ? "Tails" : ""}
          </div>
          <div className={"result-meta" + (show ? " show" : "")}>
            {result === "heads" ? "King Charles III" : result === "tails" ? "Royal Cypher" : ""}
          </div>
        </div>

        <button className="flip-btn" onClick={toss} disabled={spin}>
          {spin ? "Flipping" : "Flip"}
        </button>

        <div className="tally-card">
          <div className="t-col">
            <div className="t-num">{counts.heads}</div>
            <div className="t-lbl">Heads</div>
          </div>
          <div className="t-divider" />
          <div className="t-col">
            <div className="t-num total">{total}</div>
            <div className="t-lbl">Total</div>
          </div>
          <div className="t-divider" />
          <div className="t-col">
            <div className="t-num">{counts.tails}</div>
            <div className="t-lbl">Tails</div>
          </div>
        </div>

        <button className="reset-btn" onClick={reset} title="Reset">
          <ResetIcon />
        </button>
      </div>
    </>
  );
}
